const response = $input.item.json;
let ai_data;

// Debug: Log the raw response so we can see what Gemini answered in n8n
console.log(response);

// Try to parse the Gemini text response into a JSON object
// Output of langchain google gemini is usually in $json.text or $json.text? No it's $json.text
try {
  const rawContent = response.content || response.text || response.message || '{}';
  const cleanText = rawContent.replace(/```json/g, '').replace(/```/g, '').trim();
  ai_data = JSON.parse(cleanText);
} catch (e) {
  ai_data = { importance_score: 5, summary: "Error parsing AI response", action: "Manual review" };
}

// Prioritization logic (JS port from prioritization.py)
const importance_score = ai_data.importance_score || 5;
// For emails we don't naturally have a deadline, so neutral time_score of 10
const time_score = 10;

const base_score = (importance_score / 10.0) * 50;
let final_score = base_score + time_score;
if (final_score > 100) final_score = 100;

// Urgent if score > 75 or importance is very high
const is_urgent = final_score > 75 || importance_score >= 9;

// Build the new output item
return {
  priority_score: Math.round(final_score),
  is_urgent: is_urgent,
  importance_score: importance_score,
  summary: ai_data.summary,
  suggested_action: ai_data.action
};
